/**
 * Test-only stub for `lucide-react-native`.
 *
 * The real package depends on `react-native-svg`, which performs native
 * module resolution at import time and crashes under happy-dom. Tests
 * never assert on icon visuals — they only need named exports that
 * render *something* without throwing. We resolve every icon to the
 * same passthrough span; the list is enumerated so ESM static
 * `import { X, Y } from 'lucide-react-native'` always finds the export.
 *
 * The list was generated by walking
 * `apps/mobile/components/**` and pulling every named import from
 * `lucide-react-native`. Add new icons here when test target files
 * start using them.
 */
import { createElement, forwardRef } from 'react'

const Icon = forwardRef(function LucideIcon(
  props: Record<string, unknown>,
  ref: React.Ref<HTMLSpanElement>,
) {
  return createElement('span', {
    ref,
    'data-icon': true,
    'aria-hidden': 'true',
    ...props,
  })
})

